[{"category":"section","location":"api/#FunctionalImageFormat.jl","page":"API Reference","text":"","title":"FunctionalImageFormat.jl"},{"category":"section","location":"api/#Data-Types","page":"API Reference","text":"","title":"Data Types"},{"category":"section","location":"api/#Utilities","page":"API Reference","text":"","title":"Utilities"},{"category":"function","location":"api/#FunctionalImageFormat.read_fif","page":"API Reference","text":"read_fif(filename; header_only=false, channels=[])\n\nRead FIF data structure from a .fif file.\n\n\n\n\n\n","title":"FunctionalImageFormat.read_fif"},{"category":"function","location":"api/#FunctionalImageFormat.write_fif","page":"API Reference","text":"write_fif(filename, data::Union{FifData, FifEpochs})\n\nWrite a FifData or FifEpochs object to a .fif file.\n\n\n\n\n\n","title":"FunctionalImageFormat.write_fif"},{"category":"type","location":"api/#FunctionalImageFormat.FifData","page":"API Reference","text":"Complete data structure containing continuous FIF raw data and metadata.\n\n\n\n\n\n","title":"FunctionalImageFormat.FifData"},{"category":"type","location":"api/#FunctionalImageFormat.FifEpochs","page":"API Reference","text":"Complete data structure containing epoched or averaged FIF data and metadata.\n\n\n\n\n\n","title":"FunctionalImageFormat.FifEpochs"},{"category":"type","location":"api/#FunctionalImageFormat.FifHeader","page":"API Reference","text":"Data structure containing FIF file header information.\n\n\n\n\n\n","title":"FunctionalImageFormat.FifHeader"},{"category":"type","location":"api/#FunctionalImageFormat.FifChInfo","page":"API Reference","text":"Data structure containing information about a single FIF channel.\n\n\n\n\n\n","title":"FunctionalImageFormat.FifChInfo"},{"category":"type","location":"api/#FunctionalImageFormat.FifChPos","page":"API Reference","text":"Data structure containing the 3D position and orientation of a channel.\n\n\n\n\n\n","title":"FunctionalImageFormat.FifChPos"},{"category":"type","location":"api/#FunctionalImageFormat.FifTriggers","page":"API Reference","text":"Data structure containing FIF trigger events.\n\n\n\n\n\n","title":"FunctionalImageFormat.FifTriggers"},{"category":"function","location":"api/#FunctionalImageFormat.channel_index","page":"API Reference","text":"channel_index(labels, channels)\n\nConvert channel specifications to channel indices.\n\n\n\n\n\n","title":"FunctionalImageFormat.channel_index"},{"category":"section","location":"#FunctionalImageFormat.jl","page":"Home","text":"A native Julia package for reading and writing FIFF (Functional Image File Format) files used in MEG/EEG neuroimaging.","title":"FunctionalImageFormat.jl"},{"category":"section","location":"#Features","page":"Home","text":"Zero-dependency I/O — Read and write .fif files entirely in native Julia\nFast and Efficient — Optimized block reads with in-place byte-swap\nBit-perfect round-trips — read_fif → write_fif → read_fif produces identical data\nStandard Compliant — Output files adhere strictly to the format structure and are fully inter-operable with the wider neuroimaging ecosystem","title":"Features"},{"category":"section","location":"#Installation","page":"Home","text":"using Pkg\nPkg.add(url=\"https://github.com/igmmgi/FunctionalImageFormat.jl\")","title":"Installation"},{"category":"section","location":"#Quick-Start","page":"Home","text":"using FunctionalImageFormat\n\n# Read continuous raw data\nfif = read_fif(\"sample_raw.fif\")\nfif.data          # Matrix{Float32} [channels × time]\nfif.header.sfreq  # Sampling rate\nfif.header.ch_info # Channel metadata\nfif.triggers      # Extracted trigger events\n\n# Write back to disk\nwrite_fif(\"output_raw.fif\", fif)\n\n# Read evoked/averaged data\nevoked = read_fif(\"sample-ave.fif\")\nevoked.data       # Array{Float32,3} [channels × time × conditions]","title":"Quick Start"},{"category":"section","location":"#Supported-Data-Types","page":"Home","text":"Format Read Write\nContinuous raw (FIFFB_RAW_DATA) ✅ ✅\nEvoked/averaged (FIFFB_EVOKED) ✅ ✅\nSSP projectors (FIFFB_PROJ_ITEM) ✅ 🔜\nChannel info (96-byte structs) ✅ ✅\nTrigger extraction (STI channels) ✅ —","title":"Supported Data Types"},{"category":"section","location":"#Performance","page":"Home","text":"Benchmarked on sample data (376 channels × 14,400 samples):\n\nLibrary Time\nFunctionalImageFormat.jl ~10 ms","title":"Performance"},{"category":"section","location":"#License","page":"Home","text":"MIT","title":"License"}]
